import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.NIzFHKo_.js";const p=JSON.parse('{"title":"Identity and Multi-Tenancy Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"10_core/20_structure/10_identity.md","filePath":"10_core/20_structure/10_identity.md"}'),r={name:"10_core/20_structure/10_identity.md"};function i(c,e,s,d,l,u){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="identity-and-multi-tenancy-architecture" tabindex="-1">Identity and Multi-Tenancy Architecture <a class="header-anchor" href="#identity-and-multi-tenancy-architecture" aria-label="Permalink to &quot;Identity and Multi-Tenancy Architecture&quot;">​</a></h1><blockquote><p>Quarantine notice: this page preserves older platform and tenant-model doctrine. Treat it as reference-only until it is rewritten to match the active QiAccess Start runtime. See <code>08_appendices/20_legacy/qiaccess_start_legacy_quarantine.md</code>.</p></blockquote><h2 id="single-source-of-truth" tabindex="-1">Single Source of Truth <a class="header-anchor" href="#single-source-of-truth" aria-label="Permalink to &quot;Single Source of Truth&quot;">​</a></h2><p>Auth and Identity are completely delegated to <strong>Supabase Auth</strong>.</p><h2 id="namespace-isolation-schema-separation" tabindex="-1">Namespace Isolation &amp; Schema Separation <a class="header-anchor" href="#namespace-isolation-schema-separation" aria-label="Permalink to &quot;Namespace Isolation &amp; Schema Separation&quot;">​</a></h2><p>Do <strong>not</strong> store tenant isolation logic or multi-tenant domain data in the <code>public</code> schema.</p><ul><li><strong><code>public</code></strong>: Reserved only for global operational data, internal system profiles, and generalized reference tables (e.g., <code>profiles</code>, <code>todos</code>).</li><li><strong><code>qione</code> (or <code>tenant_data</code>)</strong>: A separate schema for all multi-tenant customer data, keeping domains strictly isolated.</li></ul><h2 id="the-rbac-tenant-structure" tabindex="-1">The RBAC &amp; Tenant Structure <a class="header-anchor" href="#the-rbac-tenant-structure" aria-label="Permalink to &quot;The RBAC &amp; Tenant Structure&quot;">​</a></h2><p>Identity operates through three primary tables:</p><ol><li><strong><code>auth.users</code></strong>: Managed natively by Supabase.</li><li><strong><code>public.organizations</code> (or <code>tenants</code>)</strong>: The canonical parent for a given tenant instance.</li><li><strong><code>public.tenant_members</code></strong>: The mapping layer that ties <code>auth.users.id</code> to <code>tenants.id</code> with a specific <code>role</code> (e.g., Owner, Admin, Member).</li></ol><h2 id="row-level-security-rls-strategy" tabindex="-1">Row Level Security (RLS) Strategy <a class="header-anchor" href="#row-level-security-rls-strategy" aria-label="Permalink to &quot;Row Level Security (RLS) Strategy&quot;">​</a></h2><p>Every mapped table in the tenant domain must contain a <code>tenant_id</code>. RLS must be universally enforced utilizing a Supabase Postgres function that pulls the resolved <code>tenant_id</code> out of the user&#39;s secure bounded context (either via a JWT claim <code>app_metadata</code> or a secure database hook <code>auth.uid() -&gt; tenant_members</code>).</p>',12)])])}const m=t(r,[["render",i]]);export{p as __pageData,m as default};
